using System.ComponentModel;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Extensions.AI;
using OpenAI;

var modelName = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY");
if (string.IsNullOrWhiteSpace(apiKey))
{
    Console.Error.WriteLine("Error: set the OPENAI_API_KEY environment variable.");
    return 1;
}

// Initialize tools
var notebook = new Notebook();
var searcher = new WebSearcher();

AITool[] tools =
[
    AIFunctionFactory.Create(searcher.SearchAsync),
    AIFunctionFactory.Create(notebook.AddNote),
    AIFunctionFactory.Create(notebook.GetNotes),
];

// Build chat client with automatic function-calling middleware
IChatClient client = new OpenAIClient(apiKey)
    .GetChatClient(modelName)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

// Ask the user for a topic
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrWhiteSpace(topic))
{
    Console.Error.WriteLine("No topic provided.");
    return 1;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");

List<ChatMessage> history =
[
    new(ChatRole.System, """
        You are a thorough research agent. Given a topic you must:
        1. Perform several web searches with varied queries to build broad coverage.
        2. Save every important finding with add_note.
        3. After collecting enough material (aim for 5+ searches), call get_notes to review.
        4. Produce a well-structured Markdown summary with headings and key take-aways.
        Keep searching until you have enough information for a comprehensive answer.
        """),
    new(ChatRole.User, $"Research this topic: {topic}"),
];

var options = new ChatOptions { Tools = [.. tools] };

// The UseFunctionInvocation middleware handles the full tool-calling loop
// automatically: LLM → tool calls → execute → feed results back → repeat.
var response = await client.GetResponseAsync(history, options);

Console.WriteLine("═══ Research Summary ═══\n");
Console.WriteLine(response.Text);

if (notebook.Notes.Count > 0)
{
    Console.WriteLine($"\n═══ Collected Notes ({notebook.Notes.Count}) ═══\n");
    for (var i = 0; i < notebook.Notes.Count; i++)
        Console.WriteLine($"  {i + 1}. {notebook.Notes[i]}");
}

return 0;

// ─── Web Search Tool ────────────────────────────────────────────────

sealed class WebSearcher
{
    private static readonly HttpClient Http = new()
    {
        DefaultRequestHeaders = { { "User-Agent", "ResearchAgent/1.0" } },
        Timeout = TimeSpan.FromSeconds(15),
    };

    [Description("Search the web and return a list of result snippets for a query.")]
    public async Task<string> SearchAsync(
        [Description("The search query string")] string query)
    {
        Console.WriteLine($"  🌐 Searching: \"{query}\"");
        try
        {
            var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
            var html = await Http.GetStringAsync(url);

            var sb = new StringBuilder();
            var rank = 0;

            foreach (Match m in Regex.Matches(
                html,
                @"<a[^>]+class=""result__a""[^>]*>(?<title>.*?)</a>.*?"
                + @"<a[^>]+class=""result__snippet""[^>]*>(?<snippet>.*?)</a>",
                RegexOptions.Singleline))
            {
                if (++rank > 8) break;
                var title = StripHtml(m.Groups["title"].Value);
                var snippet = StripHtml(m.Groups["snippet"].Value);
                sb.AppendLine($"[{rank}] {title}");
                sb.AppendLine($"    {snippet}");
                sb.AppendLine();
            }

            var results = sb.Length > 0
                ? sb.ToString()
                : "No results found. Try a different query.";
            Console.WriteLine($"  ✅ Got {rank} result(s).");
            return results;
        }
        catch (Exception ex)
        {
            Console.WriteLine($"  ⚠️  Search failed: {ex.Message}");
            return $"Search failed: {ex.Message}";
        }
    }

    private static string StripHtml(string value) =>
        Regex.Replace(
            System.Net.WebUtility.HtmlDecode(Regex.Replace(value, "<[^>]+>", "")),
            @"\s+", " ").Trim();
}

// ─── Note-Taking Tool ───────────────────────────────────────────────

sealed class Notebook
{
    public List<string> Notes { get; } = [];

    [Description("Save a research note or key finding for later reference.")]
    public string AddNote([Description("The note text to save")] string note)
    {
        Notes.Add(note);
        Console.WriteLine($"  📝 Note #{Notes.Count} saved.");
        return $"Note #{Notes.Count} saved.";
    }

    [Description("Retrieve all previously saved research notes.")]
    public List<string> GetNotes()
    {
        Console.WriteLine($"  📋 Retrieving {Notes.Count} note(s).");
        return Notes;
    }
}

